mapper.select:
select s.stat_id, s.subject_type, s.subject_id, s.visit_date, s.visit_count, s.message_count, s.flower_count, d.name as deceased_name from mem_statistics s left join mem_deceased d on s.subject_type = 0 and s.subject_id = d.deceased_id where 1=1
and s.subject_type = #{subjectType}
and s.subject_id = #{subjectId}
order by s.visit_date desc

mapper.update:
update mem_statistics
visit_count = #{visitCount}, message_count = #{messageCount}, flower_count = #{flowerCount},
where stat_id = #{statId}
